/** user-defined types **/

export type AiProviderStatus = { id: string; configured: boolean }
export type BranchInfo = { name: string; is_head: boolean; upstream: string | null; ahead: number; behind: number }
export type BranchList = { local: BranchInfo[]; remote: string[] }
/**
 * How two arbitrary refs relate: commits `ours` has that `theirs` doesn't
 * (ahead) and commits `theirs` has that `ours` doesn't (behind).
 */
export type BranchRelation = { ahead: number; behind: number }
/**
 * What to do with uncommitted changes when switching branches.
 */
export type BranchSwitchMode = 
/**
 * Stash before switching, reapply after. A conflicting reapply leaves the
 * stash intact as a backup. Most protective; the default.
 */
"auto_stash" | 
/**
 * Plain `git checkout`: carry changes to the new branch, but refuse the
 * switch if any change would be overwritten.
 */
"carry" | 
/**
 * Refuse to switch while the working tree is dirty.
 */
"refuse"
export type BuildInfo = { version: string; build_date: string; git_hash: string; debug: boolean }
export type CatalogModel = { id: string; name: string; 
/**
 * Whether the account can actually select this model. Always true for static
 * catalog entries; a live Copilot list marks plan-gated models false so the
 * picker can show them greyed out instead of hiding them.
 */
enabled: boolean }
export type CatalogProvider = { id: string; name: string; base_url: string; dialect: Dialect; models: CatalogModel[] }
/**
 * What happened to uncommitted changes during a branch switch.
 */
export type CheckoutOutcome = 
/**
 * Tree was clean, or changes carried over cleanly. Nothing to report.
 */
"clean" | 
/**
 * Changes were stashed and popped back successfully.
 */
"stashed" | 
/**
 * Changes were stashed, the switch happened, but the pop conflicted. The
 * stash was KEPT as a backup; the working tree has conflict markers.
 */
"stash_pop_conflict"
/**
 * Commit-graph column layout. Column ids are validated on the frontend, so
 * unknown values here are ignored rather than rejected.
 */
export type ColumnLayout = { 
/**
 * Column ids in display order.
 */
order?: string[]; 
/**
 * Column ids the user has hidden.
 */
hidden?: string[] }
export type CommitDetail = { sha: string; summary: string; body: string; author_name: string; author_email: string; time: number; parent_shas: string[]; files: FileChange[] }
export type CommitEntry = { sha: string; short_sha: string; summary: string; author_name: string; author_email: string; author_initials: string; 
/**
 * Unix epoch seconds.
 */
time: number; lane: number; 
/**
 * Lane of each parent edge, aligned with `parent_shas`.
 */
parent_lanes: number[]; parent_shas: string[]; is_merge: boolean; refs: RefInfo[] }
/**
 * The three sides of a conflicted file, as full text.
 */
export type ConflictContent = { path: string; 
/**
 * Common ancestor version (stage 1); empty if added on both sides.
 */
base: string; 
/**
 * Our version (stage 2, current branch).
 */
ours: string; 
/**
 * Their version (stage 3, incoming branch).
 */
theirs: string; 
/**
 * Working-tree text with conflict markers, for manual editing.
 */
merged: string; 
/**
 * Any side is binary/undecodable; only ours/theirs whole-file choice is safe.
 */
binary: boolean }
export type DeviceCodeInfo = { device_code: string; user_code: string; verification_uri: string; 
/**
 * Minimum seconds between polls.
 */
interval: number }
export type Dialect = "anthropic" | "open_ai"
export type DiffLineEntry = { 
/**
 * "+" added, "-" removed, "" context, "@" hunk header.
 */
sign: string; old_no: number | null; new_no: number | null; text: string; 
/**
 * Index into `FileDiff.hunks` this line belongs to. Hunk-header lines
 * (`sign == "@"`) also carry the index of the hunk they introduce.
 */
hunk_index: number }
export type DiffSource = { kind: "staged" } | { kind: "unstaged" } | { kind: "commit"; sha: string }
export type FileChange = { path: string; status: StatusCode; additions: number; deletions: number; conflicted: boolean; 
/**
 * Set when this path is a submodule whose pinned commit moved. Ordinary file
 * actions (stash, discard-by-checkout) can't touch it; the UI must offer
 * submodule-specific handling instead.
 */
submodule: SubmoduleMove | null }
export type FileDiff = { path: string; 
/**
 * Rename source path, when the delta is a rename.
 */
old_path: string | null; additions: number; deletions: number; hunks: HunkHeader[]; lines: DiffLineEntry[]; binary: boolean }
export type GeneratedCommitMessage = { summary: string; description: string }
export type GitProgressPayload = { repo_id: string; operation: string; line: string }
/**
 * A `@@ -old_start,old_lines +new_start,new_lines @@` hunk boundary.
 */
export type HunkHeader = { old_start: number; old_lines: number; new_start: number; new_lines: number; 
/**
 * Raw header text including any trailing section context.
 */
header: string }
export type LogPage = { commits: CommitEntry[]; has_more: boolean }
/**
 * What a merge of a given ref into HEAD would do, without performing it.
 */
export type MergeAnalysis = { 
/**
 * HEAD already contains the target; merging is a no-op.
 */
up_to_date: boolean; 
/**
 * Merge can fast-forward (no merge commit needed).
 */
can_fast_forward: boolean; 
/**
 * A real merge commit would be created.
 */
normal: boolean; 
/**
 * Short sha the target ref resolves to.
 */
target_sha: string }
/**
 * Outcome of starting a merge.
 */
export type MergeResult = { 
/**
 * HEAD already contained the target; nothing changed.
 */
up_to_date: boolean; 
/**
 * HEAD was advanced without a merge commit.
 */
fast_forwarded: boolean; 
/**
 * Paths left in a conflicted state, needing resolution.
 */
conflicts: string[] }
/**
 * Current in-progress operation state of the repo (merge or cherry-pick).
 */
export type MergeState = { 
/**
 * True when an operation is underway (a merge or cherry-pick is in progress).
 */
merging: boolean; 
/**
 * Which operation is in progress, if any.
 */
operation: OperationKind | null; 
/**
 * Branch/ref/commit being merged or picked, best-effort from the state files.
 */
incoming_label: string | null; 
/**
 * Paths still conflicted.
 */
conflicts: string[] }
/**
 * A pending index-level operation that can leave conflicts to resolve.
 */
export type OperationKind = "Merge" | "CherryPick" | "Revert"
export type PollResult = 
/**
 * Token acquired and saved; sign-in is complete.
 */
{ status: "complete" } | 
/**
 * User has not finished authorizing yet; poll again after `interval`.
 */
{ status: "pending"; interval: number }
/**
 * Outcome of a rebase. A clean rebase returns no conflicts; a paused rebase
 * (conflicts to resolve) lists the conflicted paths and leaves the repo in its
 * rebase-in-progress state.
 */
export type RebaseResult = { 
/**
 * Paths left in a conflicted state; the rebase is paused until resolved.
 */
conflicts: string[] }
export type RecentRepo = { name: string; path: string }
export type RefInfo = { name: string; type: RefKind }
export type RefKind = "head" | "branch" | "remote" | "tag"
/**
 * Where a branch ref pointed before an operation, so it can be undone.
 */
export type RefMove = { 
/**
 * The branch that moved.
 */
branch: string; 
/**
 * Full sha the branch pointed at before the move.
 */
previous_sha: string }
/**
 * A configured remote and the remote-tracking branches under it.
 */
export type RemoteInfo = { name: string; url: string; 
/**
 * Push URL when it differs from the fetch URL, else None.
 */
push_url: string | null; 
/**
 * Short branch names under this remote (without the `<remote>/` prefix),
 * e.g. `main`, `dependabot/npm/foo`. Excludes the symbolic HEAD ref.
 */
branches: string[] }
export type RepoChangedPayload = { repo_id: string }
export type RepoInfo = { id: string; name: string; path: string; head_branch: string | null }
/**
 * How far a reset rewinds: ref only, ref+index, or ref+index+working tree.
 */
export type ResetMode = 
/**
 * Move the branch ref only; index and working tree keep the changes.
 */
"Soft" | 
/**
 * Move the ref and reset the index; working tree keeps the changes.
 */
"Mixed" | 
/**
 * Move the ref, index, and working tree. Discards uncommitted work.
 */
"Hard"
export type Resolution = 
/**
 * Keep our side wholesale.
 */
{ kind: "ours" } | 
/**
 * Keep their side wholesale.
 */
{ kind: "theirs" } | 
/**
 * Use the provided, hand-edited text.
 */
{ kind: "manual"; text: string }
export type ScannedRepo = { name: string; path: string; 
/**
 * Current branch parsed from .git/HEAD as text (None when detached/unreadable).
 */
head_branch: string | null }
/**
 * One changed line the caller selected, identified by its diff line numbers.
 * Added lines carry `new_no`; removed lines carry `old_no`.
 */
export type SelectedLine = { hunk_index: number; old_no: number | null; new_no: number | null }
export type Settings = { 
/**
 * Paths of repos open in tabs, in tab order, so they can be reopened on launch.
 */
open_repos?: string[]; 
/**
 * Id of the repo that was active when the app last closed.
 */
active_repo_path?: string | null; recents?: RecentRepo[]; code_folder?: string | null; clone_directory?: string | null; update_channel?: UpdateChannel; branch_switch_mode?: BranchSwitchMode; ai_provider?: string | null; ai_model?: string | null; 
/**
 * Custom system instruction for commit-message generation. None uses the
 * built-in default (see `crate::ai::prompt::DEFAULT_INSTRUCTION`).
 */
ai_instruction?: string | null; 
/**
 * Commit-graph column order and visibility.
 */
column_layout?: ColumnLayout | null; 
/**
 * Default action for the commit button: "commit" or "commit_push". None
 * falls back to plain commit. Validated on the frontend.
 */
commit_button_mode?: string | null; 
/**
 * Show worktree actions and the worktree sidebar section. Off by default;
 * the frontend auto-enables it when a repo already has extra worktrees.
 */
enable_worktrees?: boolean }
export type StashInfo = { index: number; message: string }
/**
 * Result of a stash-save attempt. A clean working tree is a no-op, not an error.
 */
export type StashOutcome = "stashed" | "nothing_to_stash"
export type StatusCode = "A" | "M" | "D" | "R" | "!"
/**
 * How a submodule's checked-out commit differs from the commit its parent repo
 * pins. `ahead`/`behind` are the workdir commit's position relative to the
 * recorded one.
 */
export type SubmoduleMove = { path: string; 
/**
 * Commit the parent repo records for this submodule.
 */
recorded_sha: string; 
/**
 * Commit the submodule is actually checked out at, if initialized.
 */
workdir_sha: string | null; 
/**
 * Commits the workdir is ahead of the recorded commit.
 */
ahead: number; 
/**
 * Commits the workdir is behind the recorded commit.
 */
behind: number; 
/**
 * False when the submodule has not been checked out (needs init).
 */
initialized: boolean }
export type TagInfo = { name: string }
export type UpdateChannel = "stable" | "beta"
export type WorkingStatus = { staged: FileChange[]; unstaged: FileChange[] }

/** tauri-specta globals **/

import {
	invoke as TAURI_INVOKE,
	Channel as TAURI_CHANNEL,
} from "@tauri-apps/api/core";
import * as TAURI_API_EVENT from "@tauri-apps/api/event";
import { type WebviewWindow as __WebviewWindow__ } from "@tauri-apps/api/webviewWindow";

type __EventObj__<T> = {
	listen: (
		cb: TAURI_API_EVENT.EventCallback<T>,
	) => ReturnType<typeof TAURI_API_EVENT.listen<T>>;
	once: (
		cb: TAURI_API_EVENT.EventCallback<T>,
	) => ReturnType<typeof TAURI_API_EVENT.once<T>>;
	emit: null extends T
		? (payload?: T) => ReturnType<typeof TAURI_API_EVENT.emit>
		: (payload: T) => ReturnType<typeof TAURI_API_EVENT.emit>;
};

export type Result<T, E> =
	| { status: "ok"; data: T }
	| { status: "error"; error: E };

function __makeEvents__<T extends Record<string, any>>(
	mappings: Record<keyof T, string>,
) {
	return new Proxy(
		{} as unknown as {
			[K in keyof T]: __EventObj__<T[K]> & {
				(handle: __WebviewWindow__): __EventObj__<T[K]>;
			};
		},
		{
			get: (_, event) => {
				const name = mappings[event as keyof T];

				return new Proxy((() => {}) as any, {
					apply: (_, __, [window]: [__WebviewWindow__]) => ({
						listen: (arg: any) => window.listen(name, arg),
						once: (arg: any) => window.once(name, arg),
						emit: (arg: any) => window.emit(name, arg),
					}),
					get: (_, command: keyof __EventObj__<any>) => {
						switch (command) {
							case "listen":
								return (arg: any) => TAURI_API_EVENT.listen(name, arg);
							case "once":
								return (arg: any) => TAURI_API_EVENT.once(name, arg);
							case "emit":
								return (arg: any) => TAURI_API_EVENT.emit(name, arg);
						}
					},
				});
			},
		},
	);
}
